import React, { useRef } from 'react';
import { Breadcrumb, Card, message } from 'antd';
import { useIntl, useModel } from '@umijs/max';
import type { ProFormInstance } from '@ant-design/pro-form';
import ProForm, { ProFormDigit, ProFormText, ProFormSelect, ProFormCheckbox } from '@ant-design/pro-form';
import { teamInfo as queryTeamInfo, updateTeamInfo } from '@/services/api';

import { t } from '@/global';
import type { API } from '@/services/typings';
import { PageContainer } from '@ant-design/pro-layout';

const LdapView: React.FC = () => {
  const { initialState } = useModel('@@initialState');
  const { loading } = initialState!;
  const intl = useIntl();
  const formRef = useRef<ProFormInstance<API.TeamInfo>>();

  // t2() is only used for the place where t() can't be used.
  // Like `message.info()`, `message.error()`...
  const t2 = (id: string, defaultT = '') => t(id, true, defaultT || id, intl);

  const normalizeDn = (dn: string) => dn.trim().replace(/\s*([=,])\s*/g, '$1');
  const extractDc = (dn: string) => {
    // Add "," to the beginning of dn to make the regex match the first dc.
    const lowercaseStr = ',' + dn.replace(/dc=/gi, 'dc=');
    const idx = lowercaseStr.indexOf(',dc=');
    return idx == -1 ? '' : lowercaseStr.substring(idx + 1);
  }
  const checkBindDn = (pBindDn: string, pBase: string) => {
    const bindDn = normalizeDn(pBindDn);
    const base = normalizeDn(pBase);
    const dcBindDn = extractDc(bindDn);
    const dcBase = extractDc(base);
    if (dcBase == '') {
      return true;
    } else {
      if (dcBindDn == '') {
        // base will be concated to bindDn
        return true;
      } else {
        // If bind dn and base dn both contain 'dc=', bind dn should end with base dn.
        if (dcBindDn.endsWith(dcBase)) {
          return true;
        } else {
          message.error(t2('bind dn shoud end with base dn'));
          return false;
        }
      }
    }
  }

  const handleSubmit = async (info: API.TeamInfo) => {
    if (info.ldap?.bind_dn && info.ldap?.base && !checkBindDn(info.ldap?.bind_dn!, info.ldap?.base!)) {
      return;
    }
    try {
      await updateTeamInfo({ data: info });
      message.success(t2('Update LDAP info successfully.'));
    } catch (error) {
      message.error('Failed to update LDAP: ' + error);
    }
  };

  const scopeFormItem = () => {
    const content = `
    The <a href="https://en.wikipedia.org/wiki/Lightweight_Directory_Access_Protocol">scope</a> of the search.<br />
    <span style="font-weight: bold;">one</span>: The entries immediately below the base DN.<br />
    <span style="font-weight: bold;">sub</span>: The entire subtree starting at the base DN.
  `;
    return <>
      <ProFormSelect
        name={['ldap', 'scope']}
        label="Scope"
        valueEnum={{
          'one': 'one',
          'sub': 'sub',
        }}
        width="md"
        placeholder={'one'}
        tooltip={<div dangerouslySetInnerHTML={{ __html: content }} />}
      />
    </>;
  }

  return (
    <PageContainer
      breadcrumbRender={() => (
        <Breadcrumb items={[
          { title: t('menu.Settings', true) },
          { title: t('LDAP', true) },
        ]} />
      )}
    >
      {loading ? null : (
        <Card>
          <ProForm
            layout="vertical"
            onFinish={handleSubmit}
            formRef={formRef}
            labelCol={{ span: 24, offset: 0 }} labelAlign={"left"}
            request={async () => {
              try {
                const info = await queryTeamInfo();
                if (info) {
                  return info;
                }
              } catch (error) {
                message.error(error as any);
              }
              return Promise.reject();
            }}
            onValuesChange={() => { }}
          >
            <ProForm.Group>
              <ProFormText
                fieldProps={{ autoComplete: 'off' }}
                rules={[
                  {
                    required: true,
                    whitespace: true,
                  },
                  {
                    min: 4,
                    max: 100,
                  },
                ]}
                placeholder={'example.com or ldaps://example.com'}
                width="md"
                name={['ldap', 'host']}
                label={t('LDAP Host', true)}
              />
              <ProFormDigit
                label={t('LDAP Port', true)}
                name={['ldap', 'port']}
                width="md"
                min={1}
                max={65535}
                placeholder={'389'}
              />
            </ProForm.Group>
            <ProForm.Group>
              <ProFormText
                rules={[
                  {
                    required: true,
                    whitespace: true,
                  },
                  {
                    min: 4,
                    max: 100,
                  },
                ]}
                placeholder={'dc=example,dc=com'}
                width="md"
                name={['ldap', 'base']}
                label={t('Base DN', true)}
              />
              {scopeFormItem()}
            </ProForm.Group>
            <ProForm.Group>
              <ProFormText
                fieldProps={{ autoComplete: 'off' }}
                rules={[
                  {
                    whitespace: true,
                  },
                  {
                    max: 500,
                  },
                ]}
                placeholder={'admin or cn=admin,dc=example,dc=com'}
                width="md"
                name={['ldap', 'bind_dn']}
                label={t('Bind DN', true)}
              />
              <ProFormText.Password
                rules={[
                  {
                    whitespace: true,
                  },
                ]}
                width="md"
                name={['ldap', 'password']}
                label={t('Password', true)}
              />
            </ProForm.Group>
            <ProFormText
              fieldProps={{ autoComplete: 'off' }}
              // Use empty placeholder to make empty the default value.
              placeholder={''}
              width="md"
              name={['ldap', 'filter']}
              label={t('Filter', true)}
            />
            <ProFormText
              fieldProps={{ autoComplete: 'off' }}
              tooltip={t('The attribute used as the username when logging in. Default is "dn".')}
              placeholder={'dn'}
              width="md"
              name={['ldap', 'username_attr']}
              label={t('Username Attribute', true)}
            />
            <ProFormCheckbox
              width="md"
              name={['ldap', 'starttls']}
            >
              {t('StartTLS', true)}
            </ProFormCheckbox>
            <ProFormCheckbox
              width="md"
              name={['ldap', 'no_tls_verify']}
            >{t('NoTLSVerify', true)}</ProFormCheckbox>
          </ProForm>
        </Card>
      )}
    </PageContainer>
  );
};

export default LdapView;
